PRAGMA foreign_keys = ON;

-- Часть 3 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098962f","title":"Бэтмен: Человек, который смеется","author":"Патрик Зерчер,Эд Брубейкер,Дуг Манке,Шон Филлипс,Аарон Сод,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002112582/140/e1e0/__Betmen_Chelovek_kotoryj_smeetsya.jpg","isbn":"978-5-389-12689-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Даже на заре своей карьеры борца с преступностью, Бэтмен успел повидать немало темных сторон человеческой натуры — но все это не шло ни в какое сравнение с воплощенным ужасом, чей леденящий смех доносится из мрака: бледноликий, улыбающийся человек, чье безумие угрожает смести все на своем пути.  Для нового защитника Готэма первая встреча с преступником по имени Джокер станет настоящим боевым крещением, схваткой, которая на долгие годы определит его борьбу с силами хаоса и безумия.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":4,"review":"","added":9999919,"hdCover":""},{"id":"098962e","title":"Бэтмен: Год первый","author":"Фрэнк Миллер, Дэвид Мазукелли,Ричмонд Льюис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001325415/140/5a16/__Betmen_God_pervyj.jpg","isbn":"978-5-389-08074-4","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В 1986 году Фрэнк Миллер и Дэвид Маццукелли произвели эту сногсшибательную новую интерпретацию оригинального Бэтмена – и того, что сделало его тем, кто он есть. Написанный вскоре после «Возвращения Темного Рыцаря», миллеровской антиутопии о последних днях Бэтмена, «Год первый» заложил базу нового видения легендарного персонажа. Эта книга включает полную версию графического романа, новое предисловие автора, Фрэнка Миллера, и новое иллюстрированное послесловие художника, Дэвида Маццукелли. Это коллекционное издание дополнено коллекцией никогда ранее не представленных публике материалов – 40 страниц скетчей, набросков, сценарных страниц и записей на полях, которые дают представление о том, как создается современная классика.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-11","rating":4.5,"review":"Предыдущее прочтение: 2019, оценка 4","added":9999918,"hdCover":""},{"id":"098962d","title":"Супермен. Человеку, у которого есть все","author":"Алан Мур, Дэйв Гиббонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005624178/140/639e/Alan_Mur_Dejv_Gibbons__Supermen._Cheloveku_u_kotorogo_est_vse.jpg","isbn":"978-5-389-19006-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бэтмен, Чудо-Женщина и Робин пришли в Крепость Одиночества поздравить Супермена с днём рождения. Они находят друга погружённым в бессознательное состояние со странным цветком на груди. Это полуразумное растение питается человеческой аурой, для чего вступает в симбиоз с захваченной жертвой. Пока Чёрное Милосердие высасывает ауру, пленённое им существо видит сны, в которых исполняются все желания.  Всё это охотно рассказывает супергероям Монгул – тот, кто принёс цветок. Инопланетный завоеватель хочет присоединить к своей империи Землю, для чего вывел из строя сильнейшего супергероя. Друзья Супермена не намерены так это оставить…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":4.5,"review":"","added":9999917,"hdCover":""},{"id":"098962c","title":"Супермен. Что случилось с Человеком Завтрашнего Дня?","author":"Алан Мур","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004709079/140/e268/Alan_Mur__Supermen._Chto_sluchilos_s_Chelovekom_Zavtrashnego_Dnya.jpg","isbn":"978-5-389-18340-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Что случилось с Человеком Завтрашнего дня?» — не просто сюжет о Супермене и его жизни, а также планах на неё после того, как плащ героя будет повешен на гвоздь, а настоящее признание в любви к великому персонажу. Когда-нибудь даже Супермен должен будет уйти на покой, и Мур ни много ни мало взял на себя смелость поведать о том, как признавший Землю своим домом криптонец себе это представляет.  Талант Мура, усиленный сиянием славы одного из величайших персонажей комиксов, явил миру то, что стало важным моментом в истории Супермена. Для самого героя это возможность оглянуться назад, к тому мигу, когда всё началось, для читателя — шанс представить воочию всю эпичность биографии Супермена и увидеть, какой была вселенная DC несколько десятков лет назад. Когда Человек из Стали решил поставить точку…  В сингл «Супермен. Что случилось с Человеком Завтрашнего дня?» вошли два выпуска: Superman # 423 и Action Comics # 583. В 1986 году это стало своего рода финалом одной эпохи и началом других. Тех, в одной из которых спустя много лет, в 2009 году, гений нового времени Нил Гейман придумает и воплотит в жизнь один из самых необычных сюжетов о Бэтмене, где даст свою версию ответа на вопрос о том, сможет ли однажды Тёмный рыцарь уйти на покой. Эту историю, названную «Что случилось с Крестоносцем в Маске?», «Азбука» издала в прошлом году. Теперь пришло время «проводить» другого великого героя, чтобы снова приветствовать его…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":4,"review":"","added":9999916,"hdCover":""},{"id":"098962b","title":"Все звезды. Бэтмен и Робин, Чудо-Мальчик. Абсолютное издание","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006726813/140/9e7c/Frenk_Miller__Vse_zvezdy._Betmen_i_Robin_ChudoMalchik._Absolyutnoe_izdanie.jpg","isbn":"978-5-389-19392-5","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Фрэнк Миллер, однажды радикально изменивший образ Бэтмена и историю его происхождения в культовых комиксах «Бэтмен. Возвращение Темного Рыцаря» и «Бэтмен. Год Первый», а также создавший наполненный пороком и насилием «Город грехов», объединился с суперзвездой мира комиксов, художником Джимом Ли («Бэтмен. Тихо!»), чтобы нанести сокрушительный удар по Готэму и его рыцарю. «Все звезды. Бэтмен и Робин, Чудо-Мальчик» — это «безумный, неистовый приквел к революционному блокбастеру 1986-го „Бэтмен. Возвращение Темного Рыцаря“», рассказывающий историю первого Динамического Дуэта — Бэтмена и сына циркачей Дика Грейсона в образе Робина — в сатирическом, хулиганском и вызывающем ключе. Такими героев и злодеев вселенной DC до Миллера и Ли никто не изображал: просто не осмелились. По-настоящему сумасшедший комикс в коллекционном абсолютном издании со множеством допматериалов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":5,"review":"","added":9999915,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098962a","title":"Dark Knight Returns: The Golden Child #1","author":"Фрэнк Миллер,Рафаэль Грампа","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003633412/140/d3ab/__Dark_Knight_Returns_The_Golden_Child_1.jpg","isbn":"","publisher":"DC Black Label","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"Frank Miller returns to the Dark Knight Universe! It’s been three years since the events of Dark Knight III: The Master Race. Lara has spent the time learning to be more human, and Carrie Kelley has been growing into her new role as Batwoman. But a terrifying evil has returned to Gotham City, and Lara and Carrie must team up to stop this growing threat-and they have a secret weapon. Young Jonathan Kent, “the golden child,” has a power inside of him unlike anything the world has ever seen, and it’s about to be unleashed... Dark Knight Returns: The Golden Child is Frank Miller’s triumphant return to the world of the Dark Knight and joining him is the superstar artist Rafael Grampá, the mastermind behind the groundbreaking Mesmo Delivery. Following work in advertising and film, this incredible collaboration marks Grampá’s first comics work in six years, bringing his extraordinary detail and storytelling to the Dark Knight saga, resulting in a Dark Knight story like nothing you’ve ever seen before.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":2,"review":"","added":9999914,"hdCover":""},{"id":"0989629","title":"Бэтмен. Возвращение Темного Рыцаря. Последний крестовый поход","author":"Фрэнк Миллер,Брайан Азарелло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003695058/140/27f6/__Betmen._Vozvraschenie_Temnogo_Rytsarya._Poslednij_krestovyj_pohod.jpg","isbn":"978-5-389-16623-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Фрэнк Миллер вместе с соавтором Брайаном Аззарелло и художником Джоном Ромитой-младшим «возвращается» в жестокий мир «Возвращения Темного Рыцаря» и рассказывает нам о последних приключениях Бэтмена прямо перед тем, как герою пришлось уйти на покой.  Безумный Джокер вновь сидит в лечебнице Аркхем, а Брюс Уэйн с переменным успехом обучает Джейсона Тодда, нового Робина, и, по всей видимости, своего преемника. И пока Бэтмен и Робин пытаются раскрыть серию загадочных убийств, связанных с элитой Готэма, общество выражает сомнение: имеет ли Бэтмен право рисковать жизнью несовершеннолетнего? Как скажутся на психике ребенка ночи, полные опасностей и насилия? И что же задумал Джокер?..  «Последний крестовый поход» рассказывает о событиях, предшествующих культовому «Возвращению Темного Рыцаря», — в делюкс-издание увеличенного формата также включены сценарий Миллера и Аззарелло, наброски Джона Ромиты-младшего и предисловие Роберта Родригеса!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":4.5,"review":"","added":9999913,"hdCover":""},{"id":"0989628","title":"Batman: The Dark Knight: Master Race","author":"Фрэнк Миллер,Брайан Азарелло","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003190332/140/60f4/__Batman_The_Dark_Knight_Master_Race.jpg","isbn":"978-1401265137","publisher":"DC Comics","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"One of the most highly anticipated sequels of all-time is finally here in BATMAN: THE DARK KNIGHT: MASTER RACE!  In 1986, Frank Miller introduced his iconic take on Batman and changed the face of comics forever. Now, three decades after BATMAN: THE DARK KNIGHT RETURNS, Miller himself has returned with a third chapter to his groundbreaking saga.  It’s been three years since the Batman defeated Lex Luthor and saved the world from tyranny. Three years since anyone has seen Gotham City’s guardian alive. Wonder Woman, Queen of the Amazons…Hal Jordan, the Green Lantern…Superman, the Man of Steel…all of the Dark Knight’s allies have retreated from the front lines of the war against injustice.  But now a new war is beginning. An army of unimaginable power led by Superman’s own daughter is preparing to claim Earth as their new world.  The only force that can stop this master race—Batman—is dead.  Long live the new Batman…  Collecting the full nine-issue miniseries and its mini-comic tie-in issues, BATMAN: THE DARK KNIGHT: MASTER RACE features incredible artwork from comics icon Andy Kubert (FLASHPOINT), as well as Klaus Janson (THE DARK KNIGHT RETURNS), John Romita Jr. (ALL-STAR BATMAN), Eduardo Risso (100 BULLETS) and Frank Miller himself!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-10","rating":4,"review":"","added":9999912,"hdCover":""},{"id":"0989627","title":"Batman: The Dark Knight Strikes Again","author":"Frank Miller","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000298093/140/1b3a/Frank_Miller__Batman_The_Dark_Knight_Strikes_Again.jpg","isbn":"9781563899294","publisher":"DC Comics","pubDate":"2004","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Batman reemerges from his underworld civilization to battle the evils of Gotham, including power-hungry Lex Luther and Brainiac, and turns against other superheroes as he drifts closer and closer towards insanity.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-10","rating":5,"review":"","added":9999911,"hdCover":""},{"id":"0989626","title":"Бэтмен. Возвращение Темного рыцаря","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001481509/140/7230/Frenk_Miller__Betmen._Vozvraschenie_Temnogo_rytsarya.jpg","isbn":"978-5-389-08071-3","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Этот шедевр современного графического романа, на страницах которого оживают мир тьмы и человек, в чьей душе царит тьма еще более густая. Писатель и художник Фрэнк Миллер совместно с контуровщиком Клаусом Янсеном и колористкой Линн Варли заново, с чистого листа создает легенду о Бэтмене в своей саге о городе Готэме, который в ближайшем будущем, спустя десять лет после того, как Бэтмен удалился от дел, пришел в полный упадок.  На улицах пышным цветом расцвела преступность, а того, кто был Бэтменом, по-прежнему терзают воспоминания о гибели родителей. Гражданское общество рушится на глазах, и тогда Брюс Уэйн, так долго подавлявший в себе порыв выйти на защиту мирных жителей, сбрасывает наконец оковы, в которые сам себя заковал.  Темный Рыцарь возвращается в ослепительном ореоле ярости, он противостоит совершенно новому поколению преступников и не уступает им в жестокости. Вскоре к нему присоединяется Робин нового поколения — девочка по имени Кэрри Келли, которая доказывает, что незаменима точно так же, как и ее предшественники.  Однако сумеют ли Бэтмен и Робин преодолеть опасности, которые уготовили для них самые смертельные враги после нескольких лет изоляции от общества, превратившей их в форменных психопатов? А главное — останется ли хоть кто-нибудь в живых после необъявленной войны, которая вот-вот разразится между сверхдержавами — как и после стычки между теми, кто когда-то был величайшими героями на свете?  С момента первой публикации графического романа «Бэтмен. Возвращение Темного Рыцаря» прошло уже пятнадцать лет, однако он остается бесспорной классикой и входит в канон мира комиксов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-10","rating":5,"review":"","added":9999910,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989625","title":"Кризис на бесконечных Землях. Абсолютное издание","author":"Марв Вульфман,Джордж Перес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006002310/140/f59a/__Krizis_na_beskonechnyh_Zemlyah._Absolyutnoe_izdanie.jpg","isbn":"978-5-389-19210-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Вселенные погибают одна за другой… Неизвестная сила стирает их из реальности – и она вот-вот доберется до Земли-1 и Земли-2, и тогда всему сущему наступит конец. Чтобы предотвратить надвигающуюся угрозу, самым могущественным героям — и злодеям! — уцелевших миров предстоит сомкнуть ряды. Супермен, Бэтмен, Чудо-Женщина, Зеленый Фонарь, Юные Титаны и многие другие отправляются на битву с таинственным врагом, но далеко не все из них вернутся живыми…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-10","rating":4.5,"review":"","added":9999909,"hdCover":""},{"id":"0989624","title":"Клинок бессмертного. Книга 10","author":"Хироаки Самура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007396455/140/0cb9/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_10.jpg","isbn":"978-5-907576-00-1","publisher":"Alt Graph","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Все тайное рано или поздно становится явным: для Хабаки Кагимуры и Бурандо пришел час расплаты за их бесчеловечные эксперименты. Никакие препятствия не помешают Рин и Доа спасти своих близких. Однако пробраться в замок Эдо и отыскать Мандзи с Исаку — это лишь полдела, ведь затем надо вырваться из запутанных подземных лабиринтов и не только сразиться с опытнейшими мечниками, но и пробиться сквозь толпу обезумевших и практически бессмертных монстров. Хироаки Самура продолжает поражать читателей изумительной графикой и невероятно зрелищными боевыми сценами.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-09","rating":5,"review":"","added":9999908,"hdCover":""},{"id":"0989623","title":"Клинок бессмертного. Книга 9","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007396446/140/233f/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_9.jpg","isbn":"978-5-905295-97-3","publisher":"Alt Graph","pubDate":"2022","language":"Русский","series":"","genres":[],"annotation":"Новые знакомые Рин — безбашенная мечница Доа и ее молчаливый друг Исаку — попадают в очередной переплет. Не контролируя свою ярость, Доа жаждет лишь крови и не думает о последствиях. Зверские эксперименты в подземельях замка Эдо заходят слишком далеко. Количество жертв растет, и держать всё в тайне уже не получается. Город гудит от самых неправдоподобных слухов. Теперь на кону положение и даже жизнь Хабаки Кагимуры, ведь в случае провала отвечать придется именно ему. Обезумевший доктор Бурандо вплотную подобрался к разгадке тайны бессмертия, но в то же время агент Итторю уже проник в замок Эдо!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-09","rating":5,"review":"","added":9999907,"hdCover":""},{"id":"0989622","title":"Клинок бессмертного. Книга 8","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006965031/140/f770/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_8.jpg","isbn":"978-5-905295-93-5","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Действие перемещается с опасных улиц Эдо в мрачные казематы особо охраняемой тюрьмы сёгуната. Хабаки Кагимура, глава секретной службы правительства, устраивает бесчеловечные эксперименты над плененным Мандзи, чтобы раскрыть секрет его бессмертия. Кагимура не остановится ни перед чем, чтобы достичь одному ему известных целей.  Тем временем Рин безуспешно пытается отыскать своего пропавшего телохранителя, а в ее доме поселяются странные гости, которые каким-то образом связаны с Итторю. И хотя Итторю разгромлена, но не уничтожена полностью. Пока Хабаки Кагимура и Аноцу Кагэхиса плетут интриги и пытаются поймать друг друга в ловушку, Мандзи и Рин должны приложить невероятные усилия, просто чтобы выбраться живыми из этой передряги!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-09","rating":5,"review":"","added":9999906,"hdCover":""},{"id":"0989621","title":"Клинок бессмертного. Книга 7","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006965022/140/35d0/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_7.jpg","isbn":"978-5-905295-89-8","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Когда Рин наконец настигает своего кровного врага — главу мятежной школы мечников Аноцу Кагэхису — ее жажда мести угасает. В один миг все переворачивается с ног на голову: некогда всесильная Итторю разгромлена, а Аноцу вынужден скрываться и снова уйти в подполье. Когда-то основатели Итторю хотели стать самой сильной школой мечников и превратиться в карающую силу сегуната. Но теперь они должны бросить вызов всей системе, чтобы выжить! На чью сторону в этом конфликте встанут Рин и Мандзи?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-09","rating":5,"review":"","added":9999905,"hdCover":""},{"id":"0989620","title":"Клинок бессмертного. Книга 6","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006805788/140/7b35/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_6.jpg","isbn":"978-5-905295-86-7","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Сира, жестокий убийца из Мугайрю, своими зверствами настроил против себя всех соратников. Расплата за злодеяния близка, но нескончаемая ненависть дает ему силы убивать дальше. Пока заклятые друзья Магацу и Мандзи пытаются загнать этого опасного зверя, Рин наконец-то добирается до своей цели, запрятанной глубоко в горах, где сталкивается с лидером Итторю, Аноцу Кагэхисой. Но в этот раз на голову Аноцу нацелена не одна она, и теперь ей придется разбираться в водовороте интриг и борьбы за власть без помощи своего бессмертного телохранителя!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-09","rating":5,"review":"","added":9999904,"hdCover":""},{"id":"098961f","title":"Клинок бессмертного. Книга 5","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006805776/140/9dc4/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_5.jpg","isbn":"978-5-905295-85-0","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Оказывается, даже бессмертный Мандзи может умереть — если разделать его на маленькие кусочки, как дичь. В этот раз он выживает только благодаря помощи Хякурин и Сори-сэнсэя, но больше не готов безоговорочно доверять новым друзьям, ведь за каждым из них длинным шлейфом тянется темное прошлое. Для Мандзи куда более приемлемым оказывается неожиданный союз с Магацу, заклятым врагом из Итторю и искусным мечником, который преследует лишь одну цель: отомстить за свою подругу. Пока двое отщепенцев вместе отправляются в путь, каждый за своими целями, Итторю наносят ответный удар!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999903,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098961e","title":"Chew Volume 1: Tasters Choice","author":"Rob Guillory, John Layman","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236570/140/4d67/Rob_Guillory_John_Layman__Chew_Volume_1_Tasters_Choice.jpg","isbn":"978-1607061595","publisher":"Image Comics","pubDate":"2009","language":"Английский","series":"Chew","genres":[],"annotation":"Tony Chu is a detective with a secret. A weird secret. Tony Chu is Cibopathic, which means he gets psychic impressions from whatever he eats. It also means he''s a hell of a detective, as long as he doesn''t mind nibbling on the corpse of a murder victim to figure out whodunit, and why. He''s been brought on by the Special Crimes Division of the FDA, the most powerful law enforcement agency on the planet, to investigate their strangest, sickest, and most bizarre cases.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999902,"hdCover":""},{"id":"098961d","title":"Стальной Алхимик. Книга 18","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007406049/140/540d/Hiromu_Arakava__Stalnoj_Alhimik._Kniga_18.jpg","isbn":"978-5-389-21390-6","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Чтобы не дать Отцу реализовать меняющий основу мироустройства план, братья Элрик готовы пожертвовать всем. В Аместрисе долгие годы шла тайная подготовка к большому преобразованию, но, чтобы остановить зло, возомнившее себя богом, у Эдварда и Альфонса есть только одна попытка. В финальной битве им готовы помочь все, кого братья Элрик встретили во время своего долгого путешествия. Что ждет Эда, Ала, их отца Гогенгейма, друзей и соратников в конце этого путешествия? Все ли обретут то, к чему стремились? В заключительную книгу манги вошли главы 105-108 и бонусная глава.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999901,"hdCover":""},{"id":"098961c","title":"Мстители Западного побережья. Полное издание","author":"Келли Томпсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007425645/140/7159/Kelli_Tompson__Mstiteli_Zapadnogo_poberezhya._Polnoe_izdanie.jpg","isbn":"978-5-6048489-0-6","publisher":"Рамона","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ГРЯДЁТ НОВАЯ ЭРА в истории величайших героев Тихоокеанского побережья! Встречайте: Хоукай (ваша любимая Кейт Бишоп!), второй Хоукай (Клинт Бартон!), Америка Чавес, Кид Омега (Квентин Квайр!), Гвенпул (Гвендолин Пул!) и парень по прозвищу Сплав (кто?)! Всё верно: они — новые Мстители Западного побережья! И хочется верить, что им под силу спасти мир, ведь на него вот-вот обрушатся вампиры, женщины ростом с небоскрёб, местные Повелители Зла и целый косяк сухопутных акул! Держись, Калифорния! А также: без преувеличения классическая история о Хоукаях и грандиозный дебют Гвенпул!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4,"review":"","added":9999900,"hdCover":""},{"id":"098961b","title":"Клинок бессмертного. Книга 4","author":"Хироаки Самура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005913072/140/092c/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_4.jpg","isbn":"978-5-905295-77-5","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Рин и Мандзи оказались втянуты в водоворот политических интриг, и теперь объявления об их розыске висят на каждом столбе. Их враг, Аноцу, ускользает из Токио и направляется далеко в горы, чтобы посетить загадочное додзё.  За спинами бывших союзников Рин и Мандзи, оказывается, стоит таинственная грозная сила. Героям приходится разделиться, и каждый по-своему ищет выход из запертого города. И пока Мандзи прорывается силой своего меча, Рин должна будет доказать силу своего духа, чтобы продолжить задуманную месть.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999899,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098961a","title":"Клинок бессмертного. Книга 3","author":"Хироаки Самура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005913069/140/29f5/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_3.jpg","isbn":"978-5-905295-73-7","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"История о мести превращается в нечто большее! Члены сметающей старые самурайские традиции школы мечников Итторю ввязываются в рискованную политическую игру в верхних эшелонах власти сёгуната. Теперь не только Рин и Мандзи решили уничтожить мятежную школу. Бойцы загадочной группы Мугайрю предлагают героям объединить усилия, чтобы убить Аноцу и обезглавить Итторю. Но методы новых союзников ужасают Рин, и на их фоне Аноцу с приспешниками не выглядят такими уж злодеями. Цель оправдывает любые средства? Все вокруг носят маски, а чтобы нанести удар, надо точно знать, кто твой враг, а кто друг!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-08","rating":5,"review":"Предыдущее прочтение: Август 2021, оценка 4.5","added":9999898,"hdCover":""},{"id":"0989619","title":"Клинок бессмертного. Книга 2","author":"Хироаки Самура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005462517/140/3140/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_2.jpg","isbn":"978-5-905295-71-3","publisher":"Alt Graph","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Рин вместе с бессмертным телохранителем Мандзи продолжает разыскивать своих заклятых врагов в громадном муравейнике Эдо конца XVIII века, но мало-помалу идея мести за погибших родителей уже не кажется ей такой желанной. Приспешники Аноцу гибнут один за одним, и кажется, что этой кровавой вендетте не будет конца. И если у Мандзи нет сомнений в выбранном пути, то Рин уже готова бросить поиски отмщения!  «Клинок бессмертного» — самая известная и масштабная работа Хироаки Самуры («Снегурочка на весеннем ветру», «Повозка Бладхарли»), которая издавалась с 1993 по 2012 годы. В этой манге Хироаки Самура отошел от привычных канонов самурайского боевика и вновь вернул популярность этому жанру. «Клинок бессмертного» удостоился многочисленных наград, включая премию Айснера, и получил несколько экранизаций, последняя из которых вышла в 2019 году.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-08","rating":5,"review":"Предыдущее прочтение: Август 2021, оценка 4.5","added":9999897,"hdCover":""},{"id":"0989618","title":"Клинок бессмертного. Книга 1","author":"Хироаки Самура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005462514/140/ef57/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_1.jpg","isbn":"978-5-905295-70-6","publisher":"Alt Graph","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Япония, 1782 год. Мандзи — самурай-одиночка, обреченный на бессмертие. Пока он не искупит свою вину и не зарубит тысячу злодеев, кровяные черви в его теле будут заживлять любые, даже самые тяжелые раны, и не дадут ему умереть. Однажды он встречает Рин, 16-летнюю девушку, которая жаждет отомстить за смерть родителей и которая нанимает Мандзи телохранителем. Вместе они отправляются на поиски убийц ее семьи, но скоро становится ясно, что отличить друзей от врагов не так-то просто, а путь мести не всегда ведет к желанной цели.  «Клинок бессмертного» — самая известная и масштабная работа Хироаки Самуры («Снегурочка на весеннем ветру», «Повозка Бладхарли»), которая издавалась с 1993 по 2012 годы. В этой манге Хироаки Самура отошел от привычных канонов самурайского боевика и вновь вернул популярность этому жанру. «Клинок бессмертного» удостоился многочисленных наград, включая премию Айснера, и получил несколько экранизаций, последняя из которых вышла в 2019 году.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-08","rating":5,"review":"Предыдущее прочтение: Август 2021, оценка 4.5","added":9999896,"hdCover":""},{"id":"0989617","title":"Стальной алхимик. Книга 17","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007300539/140/cc37/Hiromu_Arakava__Stalnoj_alhimik._Kniga_17.jpg","isbn":"978-5-389-21140-7","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Эмоциональный накал происходящих в Централе событий достигает наивысшей точки. Сможет ли полковник Рой Мустанг принять труднейшее решение в своей жизни? Воспользуется ли Альфонс шансом наконец вернуть себе тело, даже если придется пожертвовать ради этого очень многим? Время получать ответы на непростые вопросы, стоя перед вратами Истины в центре мира… В том вошли главы 99–104 и галерея набросков.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999895,"hdCover":""},{"id":"0989616","title":"Стальной алхимик. Книга 16","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007092909/140/62cf/Hiromu_Arakava__Stalnoj_alhimik._Kniga_16.jpg","isbn":"978-5-389-20784-4","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Обстановка накалена до предела. Альфонс задействует философский камень против Кимбли и Гордыни. Централ охвачен огнем восстания, солдаты сражаются, слышны звуки выстрелов и взрывов. Алекс и Оливия Армстронг, действуя сообща, задают жару Лени, хоть этот сильнейший гомункул и называет себя самым быстрым. Вдобавок наседает еще и армия марионеток, ведомых философским камнем. Эд, Шрам, Зависть и Мэй изо всех сил пытаются противостоять противнику, когда на поле боя появляется Рой Мустанг. Задав Зависти лишь один короткий вопрос, полковник понимает, что пришло время для огненной мести... В том вошли главы 93–98 и галерея набросков.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999894,"hdCover":""},{"id":"0989615","title":"Стальной алхимик. Книга 15","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006972723/140/9e0f/Hiromu_Arakava__Stalnoj_alhimik._Kniga_15.jpg","isbn":"978-5-389-20617-5","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ни секунды покоя — у братьев Элрик и вновь обретенного ими отца Ван Гогенгейма очень много дел. Альфонс Элрик атакует гомункула: он заманивает Гордыню в ловушку — место, лишенное света, чтобы не дать сопернику использовать силы. Эдвард Элрик с командой пробираются на базу Отца, где подвергаются нападению. Своя команда из самых доверенных солдат есть и у Роя Мустанга, который возвращается в Централ. Он планирует поднять мятеж и похитить одного весьма важного человека…  В том вошли главы 87–92 и галерея набросков.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999893,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989614","title":"Стальной алхимик. Книга 14","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006805314/140/9c79/Hiromu_Arakava__Stalnoj_alhimik._Kniga_14.jpg","isbn":"978-5-389-20159-0","publisher":"Азбука","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Поиски братьев вот-вот закончатся, но прежде их ждут новые союзы и сражения. Схватка с Завистью и встреча с Ван Гогенгеймом, поражение Эда и приступы Альфонса, постепенно теряющего связь с доспехами, которые стали вместилищем его души, — все это звенья одной большой цепи. Все испытания приближают братьев Элрик к цели, ради которой они затеяли свое долгое странствие. В этот котел страстей попадает внезапный альянс с одним из гомункулов, заговор в Централе против Кинга Брэдли, похищение Альфонса и последствия коварного хода Гордыни... Эмоции накалены до предела, пружина максимально сжата, чтобы взорвать историю ошеломительным финалом. В том вошли главы 80–86.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":5,"review":"","added":9999892,"hdCover":""},{"id":"0989613","title":"Стальной алхимик. Книга 13","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006264561/140/355f/Hiromu_Arakava__Stalnoj_alhimik._Kniga_13.jpg","isbn":"978-5-389-19945-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Великолепный генерал-майор Оливия Мира Армстронг прибывает в Централ и встречается с Кингом Брэдли, который, как уже известно, не за того себя выдает. Эдвард Элрик сражается с Багровым Алхимиком и терпит поражение. Тем временем Альфонс оказывается в очень трудном положении: доспехи начинают отторгать его душу. Как долго Алу удастся оставаться в железном теле, неизвестно. Похоже, братьям нужно как можно скорее возвращать свои тела обратно. Но все эти встречи, сражения и беды меркнут в сравнении с правдой о Ван Гогенгейме, отце братьев… История об алхимиках совершает новый головокружительный поворот, заставляя серьезно волноваться о каждом из главных героев. Это пока еще не финал, хотя он уже близок!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999891,"hdCover":""},{"id":"0989612","title":"Стальной алхимик. Книга 12","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006028848/140/0424/Hiromu_Arakava__Stalnoj_alhimik._Kniga_12.jpg","isbn":"978-5-389-19502-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Лень выполняет приказ Отца, и созданный им круг почти замкнулся. Аместрис в опасности! Багровый алхимик Кимбли и генерал-лейтенант Рэйвен прибывают в Бриггскую крепость, чтобы Оливии Армстронг сделать предложение, от которого она, как им кажется, не сможет отказаться, и с радостью перейдёт на их сторону. Результат их удивит. Братьев Элрик тоже ожидает сюрприз: Винри окажется всё в той же крепости Бриггс.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999890,"hdCover":""},{"id":"0989611","title":"Стальной алхимик. Книга 11","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005877030/140/54ae/Hiromu_Arakava__Stalnoj_alhimik._Kniga_11.jpg","isbn":"978-5-389-19247-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Отряд алхимиков завершает зачистку Ишвара, Рой Мустанг вынашивает большие планы, а братья Элрик продолжают поиски Мэй и Шрама. Они могут помочь братьям понять, что случилось с их способностями к алхимии после пребывания в подземелье за Вратами. В это же время Шрам разыскивает дневники своего брата, изучавшего алхимию. В этих дневниках может содержаться секрет бессмертия. Поиски «маленькой кошатницы» приведут братьев в крепость, где командир — сестра майора Армстронга, генерал-майор Оливия Мира Армстронг! Еще более удивительное открытие о замыслах гомункулов вот-вот прорвется наружу из подземелий крепости...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999889,"hdCover":""},{"id":"0989610","title":"Стальной алхимик. Книга 10","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005576613/140/aeb3/Hiromu_Arakava__Stalnoj_alhimik._Kniga_10.jpg","isbn":"978-5-389-18760-3","publisher":"Азбука","pubDate":"2021","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Отец Эда и Ала алхимик Гогенгейм явился братьям после вымотавшей их схватки с Алчностью. В его лице Элрики прочли жестокую правду: их отец связан с гомункулами и гораздо сильнее, чем можно представить. Принц Лин взглянул в глаза страшной опасности, и теперь в его зрачках Эдвард и Альфонс видят лишь тень Алчности. Шраму вновь являет свой лик жестокое прошлое Ишвара, и в его лице молодые алхимики видят не зло, но боль. Фюрер Кинг Брэдли сбросил маску мудрого начальника, и в его взгляде и словах – недвусмысленное обещание убить Винри. Во всех этих лицах читается одно: с пути уже не сойти, его надо пройти до конца. Порой просто нет выбора. как когда-то Рой Мустанг должен был отправиться в Ишвар, хотя знал, что принесёт в те земли лишь смерть и разрушения…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-08","rating":4.5,"review":"","added":9999888,"hdCover":""},{"id":"098960f","title":"Стальной алхимик. Книга 9","author":"Хирому Аракава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005444478/140/35a5/Hiromu_Arakava__Stalnoj_alhimik._Kniga_9.jpg","isbn":"978-5-389-18381-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"На фоне политических интриг в Централе, вызванных известиями об истинной натуре Кинга Брэдли, Обжорство жаждет сожрать Роя Мустанга, но закусывает в итоге не им. Проглоченные Обжорством Эд Элрик и «принц-недоумок» Лин оказываются в очень странном месте, «по колено в кровище». Раскрыть Эду глаза на истинное предназначение места готов Зависть, заодно он поделится и другими фактами. Какое же он чудовище! Победить его в истинном облике будет непросто. В это же время оставшийся один на один с Обжорством Ал требует, чтобы гомункул отвёл его к своему истинному отцу. Лицо отца станет большим сюрпризом для Элриков…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-07","rating":5,"review":"","added":9999887,"hdCover":""}]');
